@namespace Lumeo

<div class="@($"space-y-4 {Class}".Trim())" @attributes="AdditionalAttributes">
    @ChildContent
    @if ((Filters is not null && Filters.Count > 0) || Pills != null)
    {
        <div class="flex items-center gap-2 flex-wrap">
            @if (Filters is not null)
            {
                @foreach (var f in Filters)
                {
                    var desc = f;
                    <FilterPill Label="@desc.Field" Operator="@desc.Operator" Value="@(desc.Value ?? "")"
                                OnDismiss="@(() => OnRemoveFilter.InvokeAsync(desc))" />
                }
            }
            @Pills
        </div>
    }
    @if (Actions != null)
    {
        @Actions
    }
</div>

@code {
    /// <summary>Content rendered above the pills row — typically the filter input controls (dropdowns, search box) that produce the active filters.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Manually-composed filter pills, rendered alongside any pills generated from <see cref="Filters"/>.</summary>
    [Parameter] public RenderFragment? Pills { get; set; }
    /// <summary>Trailing content rendered after the pills row — typically a "clear all" button or similar bulk action.</summary>
    [Parameter] public RenderFragment? Actions { get; set; }

    /// <summary>
    /// Data-driven filter model (#319): when supplied, the bar renders a dismissable
    /// <see cref="FilterPill"/> per descriptor (Field / Operator / Value) and raises
    /// <see cref="OnRemoveFilter"/> on dismiss. The <see cref="Pills"/> slot still
    /// works and renders alongside, so this is purely additive.
    /// </summary>
    [Parameter] public IReadOnlyList<FilterDescriptor>? Filters { get; set; }
    /// <summary>Invoked with the descriptor of a data-driven pill (from <see cref="Filters"/>) when its dismiss (×) button is clicked.</summary>
    [Parameter] public EventCallback<FilterDescriptor> OnRemoveFilter { get; set; }

    /// <summary>Additional CSS classes merged onto the root container.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>A single active filter: a field, an optional comparison operator
    /// (e.g. "=", "&gt;", "contains"), and a display value.</summary>
    public record FilterDescriptor(string Field, string? Operator = null, string? Value = null);
}

@namespace Lumeo

<Badge Variant="Badge.BadgeVariant.Secondary" Class="@($"flex items-center gap-1 ps-2 pe-1 {Class}".Trim())" @attributes="AdditionalAttributes">
    @DisplayText
    <button type="button" class="ms-1 rounded-[calc(var(--radius)*2)] hover:bg-muted p-0.5 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" aria-label="@($"Remove {Label} filter")" @onclick="OnDismiss">
        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
    </button>
</Badge>

@code {
    /// <summary>The filtered field's name, shown as the pill's leading label (and in the dismiss button's <c>aria-label</c>).</summary>
    [Parameter] public string Label { get; set; } = "";
    /// <summary>Optional comparison operator shown between Label and Value
    /// (e.g. "=", "&gt;", "contains"). When null the pill reads "Label: Value". (#319)</summary>
    [Parameter] public string? Operator { get; set; }
    /// <summary>The filter's display value, shown after <see cref="Label"/> (and <see cref="Operator"/> when set).</summary>
    [Parameter] public string Value { get; set; } = "";
    /// <summary>Invoked when the pill's dismiss (×) button is clicked.</summary>
    [Parameter] public EventCallback OnDismiss { get; set; }
    /// <summary>Additional CSS classes merged onto the pill's underlying <c>Badge</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the pill's underlying <c>Badge</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string DisplayText => string.IsNullOrEmpty(Operator) ? $"{Label}: {Value}" : $"{Label} {Operator} {Value}";
}
